function maximizeXor(nums, queries) {
    nums.sort((a, b) => a - b);
    const newQueries = queries.map((q, idx) => [q[0], q[1], idx]).sort((a, b) => a[1] - b[1]);

    const trie = new Array(200010).fill(null).map(() => new Array(2).fill(0));
    const sum = new Array(200010).fill(0);
    sum[0] = 1;

    let idx = 0, cnt = 0;
    const ans = new Array(queries.length).fill(0);

    for (const q of newQueries) {
        const [x, m, k] = q;
        let p = 0;
        while (idx < nums.length && nums[idx] <= m) {
            let cur = 0, t = nums[idx++];
            for (let i = 31; i >= 0; --i) {
                const bit = ((t >> i) & 1);
                if (!trie[cur][bit]) {
                    trie[cur][bit] = ++cnt;
                }
                cur = trie[cur][bit];
            }
            sum[cur]++;
        }
        if (!cnt) { 
            ans[k] = -1; 
            continue; 
        }
        let cur = 0, ans2 = 0;
        for (let i = 31; i >= 0; --i) {
            const bit = ((x >> i) & 1);
            if (trie[cur][bit ^ 1]) {
                cur = trie[cur][bit ^ 1];
                ans2 |= (1 << i);
            } else {
                cur = trie[cur][bit];
            }
        }
        ans[k] = ans2;
    }

    return ans;
}
