import java.util.Arrays;
import java.util.Comparator;

public int[] maximizeXor(int[] nums, int[][] queries) {
    int[][] newQueries = new int[queries.length][];
    Arrays.sort(nums);
    for (int i = 0; i < queries.length; ++i) {
        newQueries[i] = new int[]{queries[i][0], queries[i][1], i};
    }
    Arrays.sort(newQueries, Comparator.comparingInt(a -> a[1]));

    int[] ans = new int[queries.length];
    int[][] trie = new int[200010][2];
    int[] sum = new int[200010];
    sum[0] = 1;
    int idx = 0, cnt = 0;
    for (int[] q : newQueries) {
        int x = q[0], m = q[1], k = q[2], p = 0;
        while (idx < nums.length && nums[idx] <= m) {
            int cur = 0, t = nums[idx++];
            for (int i = 31; i >= 0; --i) {
                int bit = ((t >> i) & 1);
                if (trie[cur][bit] == 0) {
                    trie[cur][bit] = ++cnt;
                }
                cur = trie[cur][bit];
            }
            sum[cur]++;
        }
        if (cnt == 0) { 
            ans[k] = -1; 
            continue; 
        }
        int cur = 0, ans2 = 0;
        for (int i = 31; i >= 0; --i) {
            int bit = ((x >> i) & 1);
            if (trie[cur][bit ^ 1] != 0) {
                cur = trie[cur][bit ^ 1];
                ans2 |= (1 << i);
            } else {
                cur = trie[cur][bit];
            }
        }
        ans[k] = ans2;
    }
    return ans;
}
```


